    var count: usize = 0;
    {
        var i: usize = 1;
        while (i < len) : (i += 1) {
            if (count >= out.len) {
                break;
            }
            const curr = candles[i];
            const prev = candles[i - 1];
            const body_size = @abs(curr.close - curr.open);
            const range = curr.high - curr.low;
            const prev_body = @abs(prev.close - prev.open);
            if (range > 0.0 and (body_size / nz(range)) < 0.1) {
                if (count < out.len) {
                    out[count] = .{ .pattern_type = .doji, .index = i, .confidence = 1.0 - body_size / nz(range) };
                    count += 1;
                }
            }
            const lower_shadow = @min(curr.open, curr.close) - curr.low;
            const upper_shadow = curr.high - @max(curr.open, curr.close);
            if (range > 0.0 and lower_shadow > body_size * 2.0 and upper_shadow < body_size * 0.5) {
                if (count < out.len) {
                    out[count] = .{ .pattern_type = .hammer, .index = i, .confidence = @min(1.0, lower_shadow / nz(range)) };
                    count += 1;
                }
            }
            if (range > 0.0 and upper_shadow > body_size * 2.0 and lower_shadow < body_size * 0.5) {
                if (count < out.len) {
                    out[count] = .{ .pattern_type = .shooting_star, .index = i, .confidence = @min(1.0, upper_shadow / nz(range)) };
                    count += 1;
                }
            }
            if (prev.close < prev.open and curr.close > curr.open and curr.open <= prev.close and curr.close >= prev.open) {
                if (count < out.len) {
                    out[count] = .{ .pattern_type = .bullish_engulfing, .index = i, .confidence = @min(1.0, body_size / nz(if (prev_body != 0.0) prev_body else 1.0)) };
                    count += 1;
                }
            }
            if (prev.close > prev.open and curr.close < curr.open and curr.open >= prev.close and curr.close <= prev.open) {
                if (count < out.len) {
                    out[count] = .{ .pattern_type = .bearish_engulfing, .index = i, .confidence = @min(1.0, body_size / nz(if (prev_body != 0.0) prev_body else 1.0)) };
                    count += 1;
                }
            }
        }
    }
    return count;
}

pub fn syntheticGenerate(out: []Candle, count: usize, start_price: f64, volatility: f64, seed: u64, start_time: i64) usize {
    const n = @min(count, out.len);
    var price = start_price;
    var s = seed;
    {
        var i: usize = 0;
        while (@as(f32, @floatFromInt(i)) < n) : (i += 1) {
            s = (s *% 16807) % 2147483647;
            const r1: f64 = @as(f64, @floatFromInt(s % 2147483647)) / 2147483647.0;
            s = (s *% 16807) % 2147483647;
            const r2: f64 = @as(f64, @floatFromInt(s % 2147483647)) / 2147483647.0;
            s = (s *% 16807) % 2147483647;
            const r3: f64 = @as(f64, @floatFromInt(s % 2147483647)) / 2147483647.0;
            const open = price;
            const drift = (r1 - 0.5) * volatility * 2.0;
            const close = @max(1.0, open + drift);
            const high = @max(open, close) + r2 * volatility;
            const low = @max(0.01, @min(open, close) - r3 * volatility);
            s = (s *% 16807) % 2147483647;
            const vol: f64 = 1000.0 + @as(f64, @floatFromInt(s % 9000));
            out[i] = .{ .time = start_time - @as(i64, @intCast(n - @as(f32, @floatFromInt(i)))) * 3600, .open = round2(open), .high = round2(high), .low = round2(low), .close = round2(close), .volume = vol };
            price = close;
        }
    }
    return n;
}
